package entity_test

import (
	"math"
	"testing"

	"github.com/nikita-rulenko/heisenbug-portal/internal/entity"
)

func TestUnitBenchA6B12FBA(t *testing.T) {
	const epsilon = 1e-9

	tests := []struct {
		name     string
		items    []entity.OrderItem
		expected float64
	}{
		{
			name:     "EmptyItemsSlice",
			items:    []entity.OrderItem{},
			expected: 0,
		},
		{
			name:     "NilItemsSlice",
			items:    nil,
			expected: 0,
		},
		{
			name: "ItemWithZeroQuantity",
			items: []entity.OrderItem{
				{Quantity: 0, Price: 10.0},
			},
			expected: 0,
		},
		{
			name: "ItemWithNegativePrice",
			items: []entity.OrderItem{
				{Quantity: 2, Price: -5.0},
			},
			expected: -10.0,
		},
		{
			name: "VeryLargeQuantity",
			items: []entity.OrderItem{
				{Quantity: 1_000_000_000, Price: 0.99},
			},
			expected: 990_000_000.0,
		},
		{
			name: "MixedPositiveZeroNegative",
			items: []entity.OrderItem{
				{Quantity: 2, Price: 10.0},   // 20
				{Quantity: 0, Price: 5.0},    // 0
				{Quantity: 1, Price: -3.0},   // -3
				{Quantity: 3, Price: 0.0},    // 0
				{Quantity: 4, Price: 2.5},    // 10
			},
			expected: 37.0,
		},
	}

	for _, tc := range tests {
		tc := tc // capture range variable
		t.Run(tc.name, func(t *testing.T) {
			order := entity.Order{
				Items: tc.items,
			}
			order.CalculateTotal()
			if math.Abs(order.Total-tc.expected) > epsilon {
				t.Fatalf("unexpected total: got %v, want %v", order.Total, tc.expected)
			}
		})
	}
}

