package entity_test

import (
	"strings"
	"testing"

	"github.com/nikita-rulenko/heisenbug-portal/internal/entity"
)

func TestUnitBenchC683C42F(t *testing.T) {
	tests := []struct {
		name    string
		item    entity.NewsItem
		wantErr error
	}{
		{
			name:    "empty title",
			item:    entity.NewsItem{Title: "", Content: "Some content"},
			wantErr: entity.ErrEmptyName,
		},
		{
			name:    "empty content",
			item:    entity.NewsItem{Title: "Title", Content: ""},
			wantErr: entity.ErrEmptyContent,
		},
		{
			name:    "both empty",
			item:    entity.NewsItem{Title: "", Content: ""},
			wantErr: entity.ErrEmptyName,
		},
		{
			name:    "very long content",
			item:    entity.NewsItem{Title: "Valid", Content: strings.Repeat("a", 10001)},
			wantErr: nil,
		},
		{
			name:    "unicode title with emoji",
			item:    entity.NewsItem{Title: "Coffee ☕️", Content: "Content"},
			wantErr: nil,
		},
		{
			name:    "title only spaces",
			item:    entity.NewsItem{Title: "   ", Content: "Content"},
			wantErr: entity.ErrEmptyName,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			err := tt.item.Validate()
			if err != tt.wantErr {
				t.Fatalf("expected error %v, got %v", tt.wantErr, err)
			}
		})
	}
}

