package entity_test

// CHOICE: NewsItem.Summary — test ellipsis omission when maxRunes is exactly 3
import (
	"testing"

	"github.com/nikita-rulenko/heisenbug-portal/internal/entity"
)

func TestUnitBench3F1687B0(t *testing.T) {
	tests := []struct {
		name     string
		content  string
		maxRunes int
		want     string
	}{
		{
			name:     "shorter_than_max",
			content:  "abc",
			maxRunes: 3,
			want:     "abc",
		},
		{
			name:     "exact_boundary_no_ellipsis",
			content:  "abcdef",
			maxRunes: 3,
			want:     "abc",
		},
		{
			name:     "unicode_emoji_boundary_no_ellipsis",
			content:  "😀😁😂😃",
			maxRunes: 3,
			want:     "😀😁😂",
		},
	}
	for _, tt := range tests {
		tt := tt
		t.Run(tt.name, func(t *testing.T) {
			ni := entity.NewsItem{Content: tt.content}
			got := ni.Summary(tt.maxRunes)
			if got != tt.want {
				t.Errorf("NewsItem.Summary(%d) = %q, want %q", tt.maxRunes, got, tt.want)
			}
		})
	}
}
